import{c as t,Q as e,j as n,m as r}from"./chunks/framework.DpF7k2f3.js";const h=JSON.parse('{"title":"제10장 LlamaIndex와 벡터 데이터베이스","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ko/part3-practice/chapter10.md","filePath":"ko/part3-practice/chapter10.md","lastUpdated":1779671667000}'),o={name:"ko/part3-practice/chapter10.md"};function l(p,a,i,s,d,c){return e(),n("div",null,[...a[0]||(a[0]=[r('<h1 id="제10장-llamaindex와-벡터-데이터베이스" tabindex="-1">제10장 LlamaIndex와 벡터 데이터베이스 <a class="header-anchor" href="#제10장-llamaindex와-벡터-데이터베이스" aria-label="Permalink to &quot;제10장 LlamaIndex와 벡터 데이터베이스&quot;">​</a></h1><p>##本章에서 배울 것들</p><p>이전 챕터에서 LangChain을 배웠습니다. 이 녀석은 <strong>여러 구성 요소를 연결</strong>하는 데 뛰어납니다 - 에이전트 구축, 도구 호출, 복잡한 흐름 오케스트레이션.</p><p>하지만 문제를 발견했습니까: LangChain은 RAG를 할 수 있지만, <strong>데이터 처리와 인덱싱</strong> 부분에서는 사실 꽤薄弱합니다. 문서를 어떻게 자르고, 어떻게 효율적으로 저장하고, 어떻게 정확하게 검색하는지 - LangChain은 이러한 힘든 일을 하다 보니 좀 무력합니다.</p><p>이것이 LlamaIndex의 전문 분야입니다.</p><p>LangChain이 &quot;流程编排大师&quot;라면, LlamaIndex는 &quot;数据索引专家&quot;입니다. 그 핵심 철학은: <strong>당신의プライベート 데이터를 대규모 모델이 효율적으로 查询할 수 있게 하는 것</strong>.</p><p>이 챕터를 읽고 나면 가져갈 것들:</p><ul><li>LlamaIndex 코어 아키텍처와 설계 철학(LangChain과의 분업)</li><li><strong>고급 인덱스 유형 상세</strong>: Summary Index, Keyword Table Index, Knowledge Graph Index 선택 전략</li><li><strong>LlamaIndex + LangChain 협업</strong>: 각자의 우위 경계와 하이브리드 아키텍처 실전</li><li>벡터 데이터베이스 선택 전략: Chroma / Qdrant / Milvus / Pinecone 각자의 적용 시나리오</li><li><strong>자체 구축 vs 클라우드 서비스</strong> 비용 및 운용 비교</li></ul><hr><blockquote><p><strong>전체 번역은 곧 제공될 예정입니다. 지금은中文版을 읽으실 수 있습니다.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part3-practice/chapter10.html">中文版阅读</a></p></blockquote>',10)])])}const g=t(o,[["render",l]]);export{h as __pageData,g as default};
